from __future__ import annotations

from pathlib import Path

ROOT = Path(__file__).resolve().parent
PLANNER = ROOT / "olden_db" / "olden_db" / "planner.py"
QUERY = ROOT / "olden_db" / "olden_db" / "query.py"
QUERY_DOC = ROOT / "docs" / "query_layer.md"


def replace_once(path: Path, old: str, new: str) -> None:
    text = path.read_text(encoding="utf-8")
    if new in text:
        print(f"SKIP: {path} already contains the BE-011 change")
        return
    count = text.count(old)
    if count != 1:
        raise RuntimeError(
            f"{path}: expected one exact baseline block, found {count}. "
            "Confirm main is at the BE-011 baseline before applying."
        )
    path.write_text(text.replace(old, new, 1), encoding="utf-8")
    print(f"UPDATED: {path}")


def main() -> None:
    replace_once(PLANNER, '@dataclass(frozen=True, slots=True)\nclass PlannerResult:\n    """Successful planner result with canonical structured diagnostics."""\n\n    plan: BuildPlan\n    diagnostics: tuple[PlannerDiagnostic, ...] = ()\n\n    def __post_init__(self) -> None:\n        if not isinstance(self.plan, BuildPlan):\n            raise TypeError("plan must be a BuildPlan")\n        normalized = tuple(self.diagnostics)\n        if any(not isinstance(item, PlannerDiagnostic) for item in normalized):\n            raise TypeError("diagnostics must contain PlannerDiagnostic values")\n        object.__setattr__(self, "diagnostics", normalized)\n', '@dataclass(frozen=True, slots=True)\nclass DailyConstructionCost:\n    """Immutable construction-cost projection for one dated plan action."""\n\n    date: GameDate\n    building: BuildingKey\n    cost: ResourceCost\n\n    def __post_init__(self) -> None:\n        if not isinstance(self.date, GameDate):\n            raise TypeError("date must be a GameDate")\n        if not isinstance(self.building, BuildingKey):\n            raise TypeError("building must be a BuildingKey")\n        if not isinstance(self.cost, ResourceCost):\n            raise TypeError("cost must be a ResourceCost")\n\n\n@dataclass(frozen=True, slots=True)\nclass PlannerResult:\n    """Successful planner result with canonical structured diagnostics."""\n\n    plan: BuildPlan\n    diagnostics: tuple[PlannerDiagnostic, ...] = ()\n    daily_construction_schedule: tuple[DailyConstructionCost, ...] = ()\n\n    def __post_init__(self) -> None:\n        if not isinstance(self.plan, BuildPlan):\n            raise TypeError("plan must be a BuildPlan")\n        normalized = tuple(self.diagnostics)\n        if any(not isinstance(item, PlannerDiagnostic) for item in normalized):\n            raise TypeError("diagnostics must contain PlannerDiagnostic values")\n        object.__setattr__(self, "diagnostics", normalized)\n\n        schedule = tuple(self.daily_construction_schedule)\n        if not schedule:\n            schedule = tuple(\n                DailyConstructionCost(\n                    date=step.date,\n                    building=step.building,\n                    cost=step.individual_cost,\n                )\n                for step in self.plan.steps\n            )\n        if any(not isinstance(item, DailyConstructionCost) for item in schedule):\n            raise TypeError(\n                "daily_construction_schedule must contain DailyConstructionCost values"\n            )\n        expected = tuple(\n            (step.date, step.building, step.individual_cost)\n            for step in self.plan.steps\n        )\n        actual = tuple(\n            (item.date, item.building, item.cost)\n            for item in schedule\n        )\n        if actual != expected:\n            raise ValueError(\n                "daily_construction_schedule must project the accepted plan steps"\n            )\n        object.__setattr__(self, "daily_construction_schedule", schedule)\n')
    replace_once(QUERY, 'from .income_timeline import calculate_income_timeline\nfrom .models import BuildingKey, BuildingLevel, FactionCity, ResourceCost\nfrom .planner import (\n', 'from .income_timeline import calculate_income_timeline\nfrom .localization import LocalizationCatalog, parse_localization_file\nfrom .models import BuildingKey, BuildingLevel, FactionCity, ResourceCost\nfrom .paths import require_english_cities_localization_file\nfrom .planner import (\n')
    replace_once(QUERY, '    _data: LoadedGameData\n\n    @classmethod\n    def from_default_game_data(cls) -> "PlanningQueryService":\n        """Create a ready-to-use service from the canonical game data."""\n        return cls(load_default_game_data())\n', '    _data: LoadedGameData\n    _localization: LocalizationCatalog | None = None\n\n    @classmethod\n    def from_default_game_data(cls) -> "PlanningQueryService":\n        """Create a ready-to-use service from the canonical game data."""\n        return cls(\n            load_default_game_data(),\n            parse_localization_file(\n                require_english_cities_localization_file(),\n                language="english",\n            ),\n        )\n')
    replace_once(QUERY, '    def get_prerequisites(\n        self,\n        faction: str,\n', '    def get_building_display_text(self, building: BuildingKey) -> str:\n        """\n        Return localized display text for one canonical building identity.\n\n        Localization remains a Query Layer responsibility. Application clients\n        must not read localization catalogs or repository paths directly.\n        """\n        if not isinstance(building, BuildingKey):\n            raise TypeError("building must be a BuildingKey")\n        definition = self.get_building(\n            building.faction,\n            building.sid,\n            building.level,\n        )\n        if self._localization is None:\n            raise QueryError("localization is not configured for this query service")\n        fallback = definition.name_key or building.sid\n        return self._localization.resolve(\n            definition.name_key,\n            fallback=fallback,\n        ) or fallback\n\n    def get_prerequisites(\n        self,\n        faction: str,\n')
    replace_once(QUERY_DOC, '# Query Layer Design Specification\n', '# Query Layer Design Specification\n\n## Planning Summary Support\n\n`PlanningQueryService.generate_planner_result(...)` returns the authoritative\naccepted planning result. In addition to the existing `plan` and `diagnostics`\ncontracts, `PlannerResult` exposes:\n\n```text\ndaily_construction_schedule: tuple[DailyConstructionCost, ...]\n```\n\nEach immutable entry contains the construction date, canonical `BuildingKey`,\nand individual `ResourceCost` for one accepted plan step. The projection is\ncreated from the accepted plan during normal result construction. It does not\nperform another graph traversal or planner execution and therefore shares the\nsame result lifecycle.\n\nThe Query Layer also exposes:\n\n```text\nget_building_display_text(building: BuildingKey) -> str\n```\n\nThis operation resolves presentation text from canonical building identity.\nDesktop clients must use this operation rather than importing localization\ncatalogs, localization parsers, or repository paths.\n\nExisting `generate_build_plan(...)`, `generate_planner_result(...)`, and\n`PlanningQueryService(loaded_data)` callers remain compatible.\n')
    print("BE-011 application complete.")


if __name__ == "__main__":
    main()
